"use client"

import { useState, useEffect } from "react"
import { cn } from "../lib/utils"

const navItems = [
  { label: "PROFILE", href: "#about" },
  { label: "HISTORY", href: "#experience" },
  { label: "SHOWCASE", href: "#projects" },
  { label: "CONNECT", href: "#contact" },
]

export function Navigation() {
  const [isScrolled, setIsScrolled] = useState(false)

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50)
    }
    window.addEventListener("scroll", handleScroll)
    return () => window.removeEventListener("scroll", handleScroll)
  }, [])

  return (
    <header
      className={cn(
        "fixed top-0 left-0 right-0 z-50 transition-all duration-700",
        isScrolled ? "bg-black/80 backdrop-blur-md border-b border-white/5 py-4" : "bg-transparent py-8",
      )}
    >
      <nav className="max-w-[1400px] mx-auto px-6 md:px-12">
        <div className="flex items-center justify-between">
          <a
            href="#hero"
            className="text-sm font-medium tracking-[0.3em] uppercase group"
          >
            Yinka <span className="opacity-40 group-hover:opacity-100 transition-opacity">Salaam</span>
          </a>

          {/* Desktop Nav */}
          <ul className="hidden md:flex items-center gap-12">
            {navItems.map((item) => (
              <li key={item.href}>
                <a
                  href={item.href}
                  className="editorial-label hover:text-white transition-colors"
                >
                  {item.label}
                </a>
              </li>
            ))}
          </ul>

          <div className="flex items-center gap-6">
            <a
              href="mailto:olayinkasalaam.dev@gmail.com"
              className="editorial-label hidden lg:block hover:text-white transition-colors border-b border-white/20 pb-1"
            >
              Contact_
            </a>
            
            {/* Mobile Menu Toggle (Simplified) */}
            <button className="md:hidden editorial-label">
              Menu_
            </button>
          </div>
        </div>
      </nav>
    </header>
  )
}

