"use client"

const skillCategories = [
  {
    title: "Core Stack",
    skills: ["TypeScript", "React", "Next.js", "Tailwind CSS"],
    size: "lg",
  },
  {
    title: "Animation",
    skills: ["Framer Motion", "GSAP"],
    size: "sm",
  },
  {
    title: "UI Systems",
    skills: ["Shadcn UI", "Radix", "Chakra"],
    size: "sm",
  },
  {
    title: "Workflow",
    skills: ["Git", "Figma", "VS Code", "Vercel"],
    size: "md",
  },
]

export function SkillsSection() {
  return (
    <section id="skills" className="section-container relative border-t border-white/5">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-0">
        {/* Left Column: Label */}
        <div className="lg:col-span-4">
          <div className="sticky top-24">
            <span className="editorial-label block mb-2 opacity-50">05_CAPABILITIES</span>
            <h2 className="uppercase">Skills</h2>
          </div>
        </div>

        {/* Right Column: Bento Grid */}
        <div className="lg:col-span-8">
          <div className="grid grid-cols-2 md:grid-cols-4 border-l border-t border-white/10 reveal-anim">
            {skillCategories.map((category, index) => (
              <div 
                key={index} 
                className={`
                  p-8 border-r border-b border-white/10 hover:bg-white/[0.02] transition-colors
                  ${category.size === "lg" ? "col-span-2 md:col-span-2 row-span-2" : "col-span-1 md:col-span-2"}
                `}
              >
                <span className="editorial-label block mb-6 opacity-30 tracking-widest">
                  [{category.title.toUpperCase()}]
                </span>
                <ul className="space-y-4">
                  {category.skills.map((skill) => (
                    <li key={skill} className="text-lg md:text-xl font-medium tracking-tight uppercase">
                      {skill}
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>

          <div className="mt-12 flex items-center justify-between opacity-30">
            <span className="editorial-label">Continuous Learning_</span>
            <span className="editorial-label">Last Updated: 2024.05</span>
          </div>
        </div>
      </div>

      {/* Decorative vertical line */}
      <div className="vertical-rhythm-line left-1/3 opacity-5 hidden lg:block"></div>
    </section>
  )
}

