"use client"

const experiences = [
  {
    year: "2025",
    role: "Frontend Developer",
    company: "Learnille",
    location: "Remote",
  },
  {
    year: "2025",
    role: "Frontend Developer",
    company: "S.A Ayilara",
    location: "Contract",
  },
  {
    year: "2024",
    role: "Frontend Intern",
    company: "MIC",
    location: "Lagos, NGR",
  },
]

export function ExperienceSection() {
  return (
    <section id="experience" className="section-container relative border-t border-white/5">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-0">
        {/* Left Column: Label */}
        <div className="lg:col-span-4">
          <div className="sticky top-24">
            <span className="editorial-label block mb-2 opacity-50">03_HISTORY</span>
            <h2 className="uppercase">Experience</h2>
          </div>
        </div>

        {/* Right Column: Dossier */}
        <div className="lg:col-span-8">
          <div className="border-t border-white/10">
            {experiences.map((exp, index) => (
              <div 
                key={index} 
                className="dossier-row group hover:bg-white/[0.02] transition-colors px-4 -mx-4 reveal-anim"
                style={{ animationDelay: `${index * 100}ms` }}
              >
                <div className="grid grid-cols-4 w-full items-center">
                  <div className="col-span-1">
                    <span className="font-mono text-[11px] opacity-40">{exp.year}</span>
                  </div>
                  <div className="col-span-1">
                    <span className="text-sm font-medium uppercase tracking-tight">{exp.role}</span>
                  </div>
                  <div className="col-span-1">
                    <span className="text-sm opacity-40">{exp.company}</span>
                  </div>
                  <div className="col-span-1 text-right">
                    <span className="editorial-label opacity-20 group-hover:opacity-60 transition-opacity">
                      {exp.location}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="mt-16 pt-8 border-t border-white/5">
            <p className="text-sm text-muted-foreground max-w-md italic">
              Detailed technical specification and full project logs available upon request.
            </p>
          </div>
        </div>
      </div>

      {/* Decorative vertical line */}
      <div className="vertical-rhythm-line left-1/3 opacity-5 hidden lg:block"></div>
    </section>
  )
}

